// Each shape is defined once, in its spawn orientation, plus a pivot point -
// the center it rotates around. The other 3 rotation states are generated by
// rotating those cells 90 degrees around the pivot, repeatedly. This is how
// real Tetris implementations do it: a rigid piece spinning around a fixed
// center, not a set of independently hand-tuned per-rotation layouts.
//
// Grid y increases downward, so a screen-clockwise turn is:
//   dx' = -dy, dy' = dx   (relative to the pivot)

const BASE_SHAPES = {
    I: { cells: [ [ 0, 1 ], [ 1, 1 ], [ 2, 1 ], [ 3, 1 ] ], pivot: [ 1.5, 1.5 ] },
    O: { cells: [ [ 0, 0 ], [ 1, 0 ], [ 0, 1 ], [ 1, 1 ] ], pivot: [ 0.5, 0.5 ] },
    T: { cells: [ [ 1, 0 ], [ 0, 1 ], [ 1, 1 ], [ 2, 1 ] ], pivot: [ 1, 1 ] },
    S: { cells: [ [ 1, 0 ], [ 2, 0 ], [ 0, 1 ], [ 1, 1 ] ], pivot: [ 1, 1 ] },
    Z: { cells: [ [ 0, 0 ], [ 1, 0 ], [ 1, 1 ], [ 2, 1 ] ], pivot: [ 1, 1 ] },
    J: { cells: [ [ 0, 0 ], [ 0, 1 ], [ 1, 1 ], [ 2, 1 ] ], pivot: [ 1, 1 ] },
    L: { cells: [ [ 2, 0 ], [ 0, 1 ], [ 1, 1 ], [ 2, 1 ] ], pivot: [ 1, 1 ] },
};

function rotateCells( cells, pivot ) {
    const [ px, py ] = pivot;
    return cells.map( ( [ x, y ] ) => {
        const dx = x - px;
        const dy = y - py;
        return [ px - dy, py + dx ];
    } );
}

function buildShape( { cells, pivot } ) {
    const states = [ cells ];
    for ( let i = 1; i < 4; i++ ) states.push( rotateCells( states[ i - 1 ], pivot ) );
    const xs = cells.map( ( [ x ] ) => x );
    const box = Math.max( ...xs ) - Math.min( ...xs ) + 1;
    return { box, pivot, states };
}

export const SHAPES = Object.fromEntries(
    Object.entries( BASE_SHAPES ).map( ( [ key, shape ] ) => [ key, buildShape( shape ) ] )
);

export const COLORS = {
    I: 0x27e8ff,
    O: 0xffe14d,
    T: 0xc86bff,
    S: 0x4dff7a,
    Z: 0xff4d5e,
    J: 0x4d7aff,
    L: 0xff9f40,
};

export const SHAPE_KEYS = Object.keys( SHAPES );

// 7-bag randomizer: shuffles one of each piece per bag so runs stay fair.
export class PieceBag {
    constructor() {
        this.queue = [];
    }

    next() {
        if ( this.queue.length === 0 ) this.refill();
        return this.queue.shift();
    }

    refill() {
        const bag = [ ...SHAPE_KEYS ];
        for ( let i = bag.length - 1; i > 0; i-- ) {
            const j = Math.floor( Math.random() * ( i + 1 ) );
            [ bag[ i ], bag[ j ] ] = [ bag[ j ], bag[ i ] ];
        }
        this.queue.push( ...bag );
    }
}
